SELECT t.id, t.title, t.summary, t.category_id, c.name AS category_name, t.difficulty, t.created_at, t.updated_at FROM theory t LEFT JOIN category c ON c.id = t.category_id WHERE t.deleted_at IS NULL
AND c.name = #{categoryName}
ORDER BY t.created_at DESC

SELECT t.id, t.title, t.summary, t.category_id, c.name AS category_name, t.difficulty, t.created_at, t.updated_at FROM theory t LEFT JOIN category c ON c.id = t.category_id WHERE t.deleted_at IS NULL
AND c.name = #{category}
ORDER BY t.created_at DESC
